#include<cstdio>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
inline void print(const int &x){if(x>9)print(x/10);putchar(x%10+'0');}
inline int qpow(int a,int b,int Mod)
{
	int res=1;while(b)
	{
		if(b&1)res=1ll*res*a%Mod;
		a=1ll*a*a%Mod;b=b>>1;
	}
	return res;
}
inline bool isprime(const int &p){for(int j=2;j*j<=p;++j)if(p%j==0)return false;return true;}
int main()
{
	int n=read();if(n==1)return puts("YES\n1"),0;
	if(n==4)return puts("YES\n1\n3\n2\n4"),0;if(!isprime(n))return puts("NO"),0;
	puts("YES");int sum=1,x=1;for(int i=1;i<n;++i)
	{
		print(x);putchar('\n');
		x=1ll*qpow(sum,n-2,n)*(i+1)%n;
		sum=1ll*sum*x%n;
	}
	print(n);putchar('\n');return 0;
}
